-- ========================================================-- 更新用户钱包表结构-- 添加求购金相关字段-- ========================================================-- 检查并添加 buy_order_amount 字段ALTER TABLE user_wallet ADD COLUMN IF NOT EXISTS buy_order_amount DECIMAL(18, 2) NOT NULL DEFAULT 0.00 COMMENT '求购金' AFTER frozen_amount;-- 检查并添加 frozen_buy_order_amount 字段ALTER TABLE user_wallet ADD COLUMN IF NOT EXISTS frozen_buy_order_amount DECIMAL(18, 2) NOT NULL DEFAULT 0.00 COMMENT '冻结求购金' AFTER buy_order_amount;-- 更新表注释ALTER TABLE user_wallet COMMENT = '用户钱包表 - 包含余额、求购金等资金信息';-- 显示更新后的表结构DESCRIBE user_wallet;